234: func validateGroupVersionString(groupVersion string) error {
235: 	gv, err := schema.ParseGroupVersion(groupVersion)
236: 	if err != nil {
237: 		return err
238: 	}
239: 	if !knownGroupVersion(gv) {
240: 		return fmt.Errorf("invalid group version, allowed versions are %q", knownGroupVersions)
241: 	}
242: 	if gv != auditv1.SchemeGroupVersion {
243: 		klog.Warningf("%q is deprecated and will be removed in a future release, use %q instead", gv, auditv1.SchemeGroupVersion)
244: 	}
245: 	return nil
246: }
247: 
248: func knownGroupVersion(gv schema.GroupVersion) bool {
249: 	for _, knownGv := range knownGroupVersions {
250: 		if gv == knownGv {
251: 			return true
252: 		}
253: 	}
254: 	return false
255: }
