257: func (o *AuditOptions) AddFlags(fs *pflag.FlagSet) {
258: 	if o == nil {
259: 		return
260: 	}
261: 
262: 	fs.StringVar(&o.PolicyFile, "audit-policy-file", o.PolicyFile,
263: 		"Path to the file that defines the audit policy configuration.")
264: 
265: 	o.LogOptions.AddFlags(fs)
266: 	o.LogOptions.BatchOptions.AddFlags(pluginlog.PluginName, fs)
267: 	o.LogOptions.TruncateOptions.AddFlags(pluginlog.PluginName, fs)
268: 	o.WebhookOptions.AddFlags(fs)
269: 	o.WebhookOptions.BatchOptions.AddFlags(pluginwebhook.PluginName, fs)
270: 	o.WebhookOptions.TruncateOptions.AddFlags(pluginwebhook.PluginName, fs)
271: }
272: 
273: func (o *AuditOptions) ApplyTo(
274: 	c *server.Config,
275: ) error {
276: 	if o == nil {
277: 		return nil
278: 	}
279: 	if c == nil {
280: 		return fmt.Errorf("server config must be non-nil")
281: 	}
282: 
283: 	// 1. Build policy evaluator
284: 	evaluator, err := o.newPolicyRuleEvaluator()
285: 	if err != nil {
286: 		return err
287: 	}
288: 
289: 	// 2. Build log backend
290: 	var logBackend audit.Backend
291: 	w, err := o.LogOptions.getWriter()
292: 	if err != nil {
293: 		return err
294: 	}
295: 	if w != nil {
296: 		if evaluator == nil {
297: 			klog.V(2).Info("No audit policy file provided, no events will be recorded for log backend")
298: 		} else {
299: 			logBackend = o.LogOptions.newBackend(w)
300: 		}
301: 	}
302: 
303: 	// 3. Build webhook backend
304: 	var webhookBackend audit.Backend
305: 	if o.WebhookOptions.enabled() {
306: 		if evaluator == nil {
307: 			klog.V(2).Info("No audit policy file provided, no events will be recorded for webhook backend")
308: 		} else {
309: 			if c.EgressSelector != nil {
310: 				var egressDialer utilnet.DialFunc
311: 				egressDialer, err = c.EgressSelector.Lookup(egressselector.ControlPlane.AsNetworkContext())
312: 				if err != nil {
313: 					return err
314: 				}
315: 				webhookBackend, err = o.WebhookOptions.newUntruncatedBackend(egressDialer)
316: 			} else {
317: 				webhookBackend, err = o.WebhookOptions.newUntruncatedBackend(nil)
318: 			}
319: 			if err != nil {
320: 				return err
321: 			}
322: 		}
323: 	}
324: 
325: 	groupVersion, err := schema.ParseGroupVersion(o.WebhookOptions.GroupVersionString)
326: 	if err != nil {
327: 		return err
328: 	}
329: 
330: 	// 4. Apply dynamic options.
331: 	var dynamicBackend audit.Backend
332: 	if webhookBackend != nil {
333: 		// if only webhook is enabled wrap it in the truncate options
334: 		dynamicBackend = o.WebhookOptions.TruncateOptions.wrapBackend(webhookBackend, groupVersion)
335: 	}
336: 
337: 	// 5. Set the policy rule evaluator
338: 	c.AuditPolicyRuleEvaluator = evaluator
339: 
340: 	// 6. Join the log backend with the webhooks
341: 	c.AuditBackend = appendBackend(logBackend, dynamicBackend)
342: 
343: 	if c.AuditBackend != nil {
344: 		klog.V(2).Infof("Using audit backend: %s", c.AuditBackend)
345: 	}
346: 	return nil
347: }
