349: func (o *AuditOptions) newPolicyRuleEvaluator() (audit.PolicyRuleEvaluator, error) {
350: 	if o.PolicyFile == "" {
351: 		return nil, nil
352: 	}
353: 
354: 	p, err := policy.LoadPolicyFromFile(o.PolicyFile)
355: 	if err != nil {
356: 		return nil, fmt.Errorf("loading audit policy file: %v", err)
357: 	}
358: 	return policy.NewPolicyRuleEvaluator(p), nil
359: }
