361: func (o *AuditBatchOptions) AddFlags(pluginName string, fs *pflag.FlagSet) {
362: 	fs.StringVar(&o.Mode, fmt.Sprintf("audit-%s-mode", pluginName), o.Mode,
363: 		"Strategy for sending audit events. Blocking indicates sending events should block"+
364: 			" server responses. Batch causes the backend to buffer and write events"+
365: 			" asynchronously. Known modes are "+strings.Join(AllowedModes, ",")+".")
366: 	fs.IntVar(&o.BatchConfig.BufferSize, fmt.Sprintf("audit-%s-batch-buffer-size", pluginName),
367: 		o.BatchConfig.BufferSize, "The size of the buffer to store events before "+
368: 			"batching and writing. Only used in batch mode.")
369: 	fs.IntVar(&o.BatchConfig.MaxBatchSize, fmt.Sprintf("audit-%s-batch-max-size", pluginName),
370: 		o.BatchConfig.MaxBatchSize, "The maximum size of a batch. Only used in batch mode.")
371: 	fs.DurationVar(&o.BatchConfig.MaxBatchWait, fmt.Sprintf("audit-%s-batch-max-wait", pluginName),
372: 		o.BatchConfig.MaxBatchWait, "The amount of time to wait before force writing the "+
373: 			"batch that hadn't reached the max size. Only used in batch mode.")
374: 	fs.BoolVar(&o.BatchConfig.ThrottleEnable, fmt.Sprintf("audit-%s-batch-throttle-enable", pluginName),
375: 		o.BatchConfig.ThrottleEnable, "Whether batching throttling is enabled. Only used in batch mode.")
376: 	fs.Float32Var(&o.BatchConfig.ThrottleQPS, fmt.Sprintf("audit-%s-batch-throttle-qps", pluginName),
377: 		o.BatchConfig.ThrottleQPS, "Maximum average number of batches per second. "+
378: 			"Only used in batch mode.")
379: 	fs.IntVar(&o.BatchConfig.ThrottleBurst, fmt.Sprintf("audit-%s-batch-throttle-burst", pluginName),
380: 		o.BatchConfig.ThrottleBurst, "Maximum number of requests sent at the same "+
381: 			"moment if ThrottleQPS was not utilized before. Only used in batch mode.")
382: }
